#!/usr/bin/env node
// gen-contract-fixtures-v2.mjs — Emit a data-only Rust module from the real v2
// (solvency-with-proven-liabilities) Groth16 fixtures so the contract v2 test
// verifies ACTUAL proofs through the on-chain pairing check (no mock VK).
//
// Reads:
//   fixtures/v2/verification_key.json
//   fixtures/v2/{solvent,insolvent}/{proof,public}.json
// Writes:
//   contracts/stellaris/src/test_fixtures_v2.rs   (@generated, data only)
//
// v2 statement has 5 public signals:
//   [ solvent, reserveCommitment, liabRoot, liabTotal, period ]
// so VK.ic length is 6. Reuses the same G1c/G2c/ProofData/VkData types from
// test_fixtures.rs (this module only adds v2 constants), and the same
// snarkjs [c0,c1] Fp2 ordering preserved as (x1=c0, x2=c1).
//
// Usage: node setup/gen-contract-fixtures-v2.mjs

import { readFileSync, writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const ROOT = join(dirname(fileURLToPath(import.meta.url)), "..");
const FIX = join(ROOT, "fixtures", "v2");
const OUT = join(ROOT, "contracts/stellaris/src/test_fixtures_v2.rs");

const rd = (p) => JSON.parse(readFileSync(p, "utf8"));

function g1(arr) {
  return { x: String(arr[0]), y: String(arr[1]) };
}
function g2(arr) {
  return {
    x1: String(arr[0][0]),
    x2: String(arr[0][1]),
    y1: String(arr[1][0]),
    y2: String(arr[1][1]),
  };
}

const vk = rd(join(FIX, "verification_key_v2.json"));
const vkData = {
  alpha: g1(vk.vk_alpha_1),
  beta: g2(vk.vk_beta_2),
  gamma: g2(vk.vk_gamma_2),
  delta: g2(vk.vk_delta_2),
  ic: vk.IC.map(g1),
};

function scenario(name) {
  const proof = rd(join(FIX, name, "proof.json"));
  const signals = rd(join(FIX, name, "public.json")).map(String);
  return {
    a: g1(proof.pi_a),
    b: g2(proof.pi_b),
    c: g1(proof.pi_c),
    signals,
  };
}

const solvent = scenario("solvency");
const insolvent = scenario("insolvent");

const g1Lit = (g) => `G1c { x: "${g.x}", y: "${g.y}" }`;
const g2Lit = (g) =>
  `G2c { x1: "${g.x1}", x2: "${g.x2}", y1: "${g.y1}", y2: "${g.y2}" }`;
const sigLit = (s) => `[${s.map((v) => `"${v}"`).join(", ")}]`;
const icLit = (ic) => ic.map((g) => `    ${g1Lit(g)},`).join("\n");

function proofConst(name, ident, p) {
  return `/// Real v2 Groth16 proof + 5 public signals for the ${name} scenario.
pub const ${ident}: ProofDataV2 = ProofDataV2 {
    a: ${g1Lit(p.a)},
    b: ${g2Lit(p.b)},
    c: ${g1Lit(p.c)},
    signals: ${sigLit(p.signals)},
};`;
}

const body = `//! @generated by setup/gen-contract-fixtures-v2.mjs — DO NOT EDIT BY HAND.
//!
//! Real v2 Groth16 (BLS12-381) verification key, proofs, and 5 public signals
//! for the solvency-with-proven-liabilities statement (por_v2.circom), produced
//! by setup/ceremony-v2.sh + setup/export-fixtures-v2.sh. Genuine cryptographic
//! artifacts — the contract v2 test verifies them through the real on-chain
//! pairing check.
//!
//! Public-signal order (5): [ solvent, reserveCommitment, liabRoot, liabTotal, period ]
//!
//! Regenerate after re-running the v2 ceremony:
//!   node setup/gen-contract-fixtures-v2.mjs

#![cfg(test)]

use crate::test_fixtures::{G1c, G2c};

/// A v2 scenario's proof (A,C in G1; B in G2) and its 5 public signals.
pub struct ProofDataV2 {
    pub a: G1c,
    pub b: G2c,
    pub c: G1c,
    pub signals: [&'static str; 5],
}

/// v2 verification key (IC length = 6 = 5 signals + 1).
pub struct VkDataV2 {
    pub alpha: G1c,
    pub beta: G2c,
    pub gamma: G2c,
    pub delta: G2c,
    pub ic: &'static [G1c],
}

/// Real v2 verification key from the solvency-with-liabilities trusted setup.
pub const VK_V2: VkDataV2 = VkDataV2 {
    alpha: ${g1Lit(vkData.alpha)},
    beta: ${g2Lit(vkData.beta)},
    gamma: ${g2Lit(vkData.gamma)},
    delta: ${g2Lit(vkData.delta)},
    ic: &[
${icLit(vkData.ic)}
    ],
};

${proofConst("solvent", "SOLVENT_V2", solvent)}

${proofConst("insolvent", "INSOLVENT_V2", insolvent)}
`;

writeFileSync(OUT, body);
console.log(`[OK] wrote ${OUT}`);
console.log(`     VK_V2.ic length: ${vkData.ic.length} (expect 6)`);
console.log(`     solvent signals:   ${sigLit(solvent.signals)}`);
console.log(`     insolvent signals: ${sigLit(insolvent.signals)}`);
